import React, { useEffect, useState } from 'react';
import api from '../api';

const PatientList = () => {
  const [patients, setPatients] = useState<any[]>([]);
  
  // States para sa Pag-Add og Bag-o
  const [fName, setFName] = useState('');
  const [lName, setLName] = useState('');
  const [dob, setDob] = useState('');
  const [gender, setGender] = useState('Male');
  const [contact, setContact] = useState('');
  const [email, setEmail] = useState('');

  // States para sa Inline Editing
  const [editingId, setEditingId] = useState<number | null>(null);
  const [editFName, setEditFName] = useState('');
  const [editLName, setEditLName] = useState('');

  const fetchPatients = () => {
    api.get('patients/').then((res: any) => setPatients(res.data));
  };

  useEffect(() => { fetchPatients(); }, []);

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // Gi-match ang keys sa imong Django models.py
      await api.post('patients/', {
        first_name: fName,
        last_name: lName,
        date_of_birth: dob,
        gender: gender,
        contact_number: contact,
        email: email
      });
      // I-reset ang form human sa malampuson nga pag-add
      setFName(''); setLName(''); setDob(''); setContact(''); setEmail('');
      fetchPatients();
      alert("Patient added successfully!");
    } catch (err: any) {
      console.error("Patient Add Error:", err.response?.data);
    }
  };

  const handleUpdate = async (id: number) => {
    try {
      // Magpadala og PUT request para sa update
      await api.put(`patients/${id}/`, {
        first_name: editFName,
        last_name: editLName,
        // Kinahanglan ipadala gihapon ang ubang required fields base sa model
        date_of_birth: dob || '2000-01-01', 
        gender: gender,
        contact_number: contact,
        email: email
      });
      setEditingId(null);
      fetchPatients();
    } catch (err: any) {
      console.error("Update Error:", err.response?.data);
    }
  };

  const handleDelete = async (id: number) => {
    if (window.confirm("Sigurado ka i-delete ni nga pasyente?")) {
      await api.delete(`patients/${id}/`);
      fetchPatients();
    }
  };

  return (
    <div className="space-y-6">
      {/* --- ADD PATIENT FORM --- */}
      <form onSubmit={handleAdd} className="grid grid-cols-1 md:grid-cols-3 gap-3 bg-green-50 p-6 rounded-xl border border-green-100 shadow-sm">
        <input className="border p-2 rounded" placeholder="First Name" value={fName} onChange={e => setFName(e.target.value)} required />
        <input className="border p-2 rounded" placeholder="Last Name" value={lName} onChange={e => setLName(e.target.value)} required />
        <input className="border p-2 rounded" type="date" value={dob} onChange={e => setDob(e.target.value)} required />
        <select className="border p-2 rounded" value={gender} onChange={e => setGender(e.target.value)}>
          <option value="Male">Male</option>
          <option value="Female">Female</option>
        </select>
        <input className="border p-2 rounded" placeholder="Contact #" value={contact} onChange={e => setContact(e.target.value)} required />
        <input className="border p-2 rounded" type="email" placeholder="Email Address" value={email} onChange={e => setEmail(e.target.value)} required />
        <button type="submit" className="md:col-span-3 bg-green-600 text-white font-bold py-2 rounded-lg hover:bg-green-700 transition">
          + Register New Patient
        </button>
      </form>

      {/* --- PATIENT TABLE --- */}
      <div className="bg-white rounded-xl shadow-md overflow-hidden border">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Patient Name</th>
              <th className="px-6 py-3 text-left text-xs font-bold text-gray-500 uppercase">Contact/Email</th>
              <th className="px-6 py-3 text-center text-xs font-bold text-gray-500 uppercase">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {patients.map((p: any) => (
              <tr key={p.patient_id} className="hover:bg-gray-50">
                {editingId === p.patient_id ? (
                  // --- EDIT MODE ---
                  <>
                    <td className="px-6 py-4 space-x-1">
                      <input className="border p-1 rounded w-24" value={editFName} onChange={e => setEditFName(e.target.value)} />
                      <input className="border p-1 rounded w-24" value={editLName} onChange={e => setEditLName(e.target.value)} />
                    </td>
                    <td className="px-6 py-4">Editing...</td>
                    <td className="px-6 py-4 text-center space-x-2">
                      <button onClick={() => handleUpdate(p.patient_id)} className="text-green-600 font-bold">Save</button>
                      <button onClick={() => setEditingId(null)} className="text-gray-400">Cancel</button>
                    </td>
                  </>
                ) : (
                  // --- VIEW MODE ---
                  <>
                    <td className="px-6 py-4 text-sm font-medium text-gray-800">{p.first_name} {p.last_name}</td>
                    <td className="px-6 py-4 text-sm text-gray-600">
                      <div>{p.contact_number}</div>
                      <div className="text-xs text-gray-400">{p.email}</div>
                    </td>
                    <td className="px-6 py-4 text-center space-x-4">
                      <button onClick={() => { setEditingId(p.patient_id); setEditFName(p.first_name); setEditLName(p.last_name); }} className="text-blue-600 hover:underline">Edit</button>
                      <button onClick={() => handleDelete(p.patient_id)} className="text-red-600 hover:underline">Delete</button>
                    </td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default PatientList;
